import React from "react";

const ContenedorLateral = ({
  subtitulo,
  imagen,
  ancho,
  alto,
  ovaloRedondez,
  cuadroRedondez,
}) => {
  // Responsive oval dimensions
  const ovaloAncho = "clamp(200px, 40%, 300px)";
  const ovaloAlto = "clamp(40px, 8vh, 60px)";

  return (
    <div
      className="relative flex flex-col items-center justify-start z-10 shadow-lg ml-auto bg-surface-elevated border border-stroke"
      style={{
        width: ancho,
        height: alto,
        borderColor: '#1E40AF',
        borderWidth: 'clamp(2px, 0.618vh, 4px)',
        borderStyle: 'solid',
        borderRadius: `${cuadroRedondez} 0 0 ${cuadroRedondez}`,
        marginTop: "clamp(2rem, 6.18vh, 4rem)",
      }}
    >
      {/* Contenedor padre que incluye el óvalo y el contenido */}
      <div className="relative w-full h-full flex flex-col items-center justify-start">
        {/* Subtítulo en óvalo */}
        <div
          className="absolute bg-surface-elevated shadow-md px-2 md:px-4 py-1 md:py-2 flex items-center justify-center border border-stroke"
          style={{
            letterSpacing: "clamp(0.1rem, 0.1618rem, 0.2rem)",
            fontSize: "clamp(0.875rem, 1.2vw, 1.5rem)",
            borderRadius: ovaloRedondez,
            left: "50%",
            top: "clamp(-8%, -6.18%, -4%)",
            transform: "translateX(-50%)",
            maxWidth: ovaloAncho,
            width: "auto",
            minWidth: "200px",
            height: ovaloAlto,
            borderColor: '#E5E7EB',
            borderWidth: 'clamp(1px, 0.1618vh, 2px)',
            borderStyle: 'solid',
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
          }}
        >
          <span className="font-bodoni text-primary font-bold text-center">
            {subtitulo}
          </span>
        </div>

        {/* Contenido dentro del contenedor - Responsive spacing */}
        <div
          className="w-full text-sm text-center"
          style={{
            marginTop: "clamp(3rem, 8vh, 5rem)",
          }}
        >
          {/* Contenedor de la imagen - Responsive dimensions */}
          <div
            className="flex justify-center items-center"
            style={{
              width: "clamp(200px, 60%, 400px)",
              height: "clamp(150px, 40vh, 300px)",
              margin: "0 auto",
              overflow: "hidden",
            }}
          >
            <img
              src={imagen}
              alt="contenido dinámico"
              className="object-contain transition-transform duration-300 hover:scale-105 w-full h-full"
              style={{
                borderRadius: ovaloRedondez,
                display: "block",
              }}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default ContenedorLateral;
